{"report_type": "HTML", "html": "<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8" />
<style>
  @page { size: A4 landscape; margin: 10mm 12mm 8mm 12mm; }
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: Arial, Helvetica, sans-serif; font-size: 8.5pt; color: #1a1a2e; background: #fff; }
  .page { max-width: 100%; margin: 0; padding: 0; }

  .hotel-logo { max-height: 52px; max-width: 95px; }
  .logo-box { display: inline-block; width: 44px; height: 44px; background: #1a1a2e; color: #fff; font-size: 15pt; font-weight: 700; text-align: center; line-height: 44px; border-radius: 5px; }
  .hotel-name { font-size: 13pt; font-weight: 700; color: #1a1a2e; }
  .hotel-sub { font-size: 7pt; color: #6b7280; margin-top: 2px; line-height: 1.5; }
  .doc-title { font-size: 12pt; font-weight: 700; color: #1a1a2e; }
  .doc-subtitle { font-size: 7pt; color: #6b7280; text-transform: uppercase; letter-spacing: 0.8px; margin-top: 2px; }
  .doc-ref { font-size: 8pt; color: #6b7280; margin-top: 6px; line-height: 1.7; }
  .doc-ref strong { color: #374151; }
  .header-divider { border: none; border-top: 2px solid #1a1a2e; margin: 12px 0 14px; }

  .pill { display: inline-block; padding: 2px 9px; border-radius: 10px; font-size: 7pt; font-weight: 700; text-transform: uppercase; letter-spacing: 0.4px; margin-right: 5px; border: 1px solid #d1d5db; background: #f9fafb; color: #374151; }
  .pills-row { margin-bottom: 12px; }

  .section-title { font-size: 7.5pt; font-weight: 700; color: #1a1a2e; text-transform: uppercase; letter-spacing: 0.6px; background: #f1f3f8; border-left: 3px solid #1a1a2e; border-bottom: 1px solid #d1d5db; padding: 5px 9px; margin-top: 14px; margin-bottom: 8px; }

  .info-table { width: 100%; border-collapse: collapse; margin-bottom: 4px; }
  .info-table td { padding: 4px 8px; font-size: 8.5pt; border-bottom: 1px solid #f1f5f9; vertical-align: middle; white-space: nowrap; }
  .info-table tr:last-child td { border-bottom: none; }
  .info-key { width: 14%; color: #1a1a2e; font-weight: 700; }
  .info-val { width: 19%; color: #1a1a2e; }

  .stats-table { width: 100%; border-collapse: collapse; margin-bottom: 8px; }
  .stats-table td { border: 1px solid #e5e7eb; padding: 5px 8px; text-align: center; }
  .s-label { font-size: 6.5pt; color: #9ca3af; display: block; text-transform: uppercase; letter-spacing: 0.4px; }
  .s-value { font-size: 11pt; font-weight: 700; color: #1a1a2e; display: block; margin-top: 2px; }
  .s-value.green { color: #15803d; }
  .s-value.red { color: #dc2626; }
  .s-value.amber { color: #d97706; }

  .panel-table { width: 100%; border-collapse: collapse; margin-bottom: 8px; }
  .panel-table td { vertical-align: top; padding: 0 6px 0 0; }
  .panel-table td:last-child { padding-right: 0; }
  .panel { border: 1px solid #e5e7eb; padding: 8px; background: #fff; }
  .panel-title { font-size: 7.5pt; font-weight: 700; color: #1a1a2e; text-transform: uppercase; letter-spacing: 0.4px; margin-bottom: 6px; border-bottom: 2px solid #1a1a2e; padding-bottom: 4px; }
  .mini-table { width: 100%; border-collapse: collapse; font-size: 8pt; }
  .mini-table thead th { background: #f1f3f8; color: #1a1a2e; padding: 4px 6px; font-size: 6.5pt; font-weight: 700; text-transform: uppercase; text-align: left; border-bottom: 2px solid #1a1a2e; }
  .mini-table thead th.num { text-align: right; }
  .mini-table td { padding: 4px 6px; border-bottom: 1px solid #f1f5f9; }
  .mini-table tr:last-child td { border-bottom: none; }
  .mini-table td.num { text-align: right; }

  .data-table { width: 100%; border-collapse: collapse; font-size: 7.5pt; margin-bottom: 4px; }
  .data-table thead tr { background: #f1f3f8; color: #1a1a2e; border-bottom: 2px solid #1a1a2e; }
  .data-table thead th { padding: 5px 5px; text-align: left; font-size: 6.5pt; font-weight: 700; text-transform: uppercase; letter-spacing: 0.3px; white-space: nowrap; border-bottom: 2px solid #1a1a2e; }
  .data-table thead th.num { text-align: right; }
  .data-table thead th.ctr { text-align: center; }
  .data-table tbody tr:nth-child(even) { background: #f9fafb; }
  .data-table tbody td { padding: 5px 5px; border-bottom: 1px solid #f1f5f9; color: #374151; vertical-align: middle; }
  .data-table tbody td.num { text-align: right; font-variant-numeric: tabular-nums; }
  .data-table tbody td.ctr { text-align: center; }
  .data-table tfoot tr { border-top: 2px solid #1a1a2e; background: #f1f3f8; color: #1a1a2e; }
  .data-table tfoot td { padding: 6px 5px; font-weight: 700; color: #1a1a2e; font-size: 8pt; }
  .data-table tfoot td.num { text-align: right; }

  .badge { display: inline-block; padding: 1px 6px; border-radius: 8px; font-size: 6.5pt; font-weight: 700; text-transform: uppercase; white-space: nowrap; }
  .badge-paid   { background: #dcfce7; color: #166534; border: 1px solid #bbf7d0; }
  .badge-part   { background: #fef3c7; color: #b45309; border: 1px solid #fde68a; }
  .badge-unpaid { background: #fee2e2; color: #b91c1c; border: 1px solid #fecaca; }
  .badge-room   { background: #dbeafe; color: #1d4ed8; border: 1px solid #bfdbfe; }
  .badge-muted  { background: #f3f4f6; color: #4b5563; border: 1px solid #e5e7eb; }
  .ref { font-family: monospace; background: #f3f4f6; color: #374151; padding: 1px 4px; border-radius: 3px; font-size: 7pt; white-space: nowrap; }

  .footer-divider { border: none; border-top: 1px solid #e5e7eb; margin: 14px 0 8px; }
  .footer-note { font-size: 7pt; color: #9ca3af; line-height: 1.7; }
  .footer-company { font-size: 9pt; font-weight: 700; color: #1a1a2e; }
  .footer-date { font-size: 7pt; color: #9ca3af; margin-top: 2px; }
  .sig-line { margin-top: 14px; border-top: 1px solid #e5e7eb; padding-top: 5px; font-size: 7pt; color: #9ca3af; text-align: center; }
</style>
</head>
<body>
<div class="page">

  <!-- HEADER -->
  <table width="100%" cellpadding="0" cellspacing="0">
    <tr>
      <td width="55%" valign="top">
        <table cellpadding="0" cellspacing="0">
          <tr>
            <td style="padding-right:10px;" valign="middle">
              {% if hotel_logo %}
                <img src="{{ hotel_logo }}" alt="{{ company }}" class="hotel-logo" />
              {% else %}
                <div class="logo-box">{{ (company or 'H')[:1] }}</div>
              {% endif %}
            </td>
            <td valign="middle">
              <div class="hotel-name">{{ company }}</div>
              <div class="hotel-sub">
                {% if hotel_tagline %}{{ hotel_tagline }}<br>{% endif %}
                {% if hotel_address %}{{ hotel_address }}<br>{% endif %}
                {% if hotel_phone %}{{ hotel_phone }}{% if hotel_email %} &middot; {% endif %}{% endif %}
                {% if hotel_email %}{{ hotel_email }}{% endif %}
              </div>
            </td>
          </tr>
        </table>
      </td>
      <td valign="top" align="right">
        <div class="doc-title">POS Sales Performance</div>
        <div class="doc-subtitle">Point of Sale Report</div>
        <div class="doc-ref">
          <strong>Period:</strong> {{ filters.date_from }} &ndash; {{ filters.date_to }}<br>
          <strong>Generated:</strong> {{ generated_at }}<br>
          <strong>Prepared By:</strong> {{ prepared_by }}
        </div>
      </td>
    </tr>
  </table>
  <hr class="header-divider" />

  <!-- PILLS -->
  <div class="pills-row">
    <span class="pill">{{ filters.date_from }} &ndash; {{ filters.date_to }}</span>
    {% if filters.pos_profile and filters.pos_profile != 'All POS Profiles' %}<span class="pill">{{ filters.pos_profile }}</span>{% endif %}
    {% if filters.cashier and filters.cashier != 'All Cashiers' %}<span class="pill">{{ filters.cashier }}</span>{% endif %}
    {% if filters.payment_mode and filters.payment_mode != 'All Payment Modes' %}<span class="pill">{{ filters.payment_mode }}</span>{% endif %}
  </div>

  <!-- FILTERS -->
  <div class="section-title">Report Filters</div>
  <table class="info-table" cellpadding="0" cellspacing="0">
    <colgroup>
      <col style="width:14%" /><col style="width:19%" />
      <col style="width:14%" /><col style="width:19%" />
      <col style="width:14%" /><col style="width:19%" />
    </colgroup>
    <tr>
      <td class="info-key">Date From</td><td class="info-val">{{ filters.date_from }}</td>
      <td class="info-key">Date To</td><td class="info-val">{{ filters.date_to }}</td>
      <td class="info-key">POS Profile</td><td class="info-val">{{ filters.pos_profile or 'All POS Profiles' }}</td>
    </tr>
    <tr>
      <td class="info-key">Cashier</td><td class="info-val">{{ filters.cashier or 'All Cashiers' }}</td>
      <td class="info-key">Payment Mode</td><td class="info-val">{{ filters.payment_mode or 'All Payment Modes' }}</td>
      <td class="info-key">Search</td><td class="info-val">{{ filters.search or '&mdash;' }}</td>
    </tr>
  </table>

  <!-- SUMMARY -->
  <div class="section-title">Summary</div>
  <table class="stats-table" cellpadding="0" cellspacing="0">
    <tr>
      <td><span class="s-label">Gross Sales</span><span class="s-value" style="font-size:9pt;">&#x20a6;{{ "{:,.0f}".format(summary.gross_sales | float) }}</span></td>
      <td><span class="s-label">Net Sales</span><span class="s-value green" style="font-size:9pt;">&#x20a6;{{ "{:,.0f}".format(summary.net_sales | float) }}</span></td>
      <td><span class="s-label">Total Orders</span><span class="s-value">{{ summary.total_orders or 0 }}</span></td>
      <td><span class="s-label">Avg Order Value</span><span class="s-value" style="font-size:9pt;">&#x20a6;{{ "{:,.0f}".format(summary.average_order_value | float) }}</span></td>
      <td><span class="s-label">Discounts</span><span class="s-value amber" style="font-size:9pt;">&#x20a6;{{ "{:,.0f}".format(summary.total_discount | float) }}</span></td>
      <td><span class="s-label">Outstanding</span><span class="s-value red" style="font-size:9pt;">&#x20a6;{{ "{:,.0f}".format(summary.outstanding | float) }}</span></td>
    </tr>
  </table>

  <!-- PAYMENT BREAKDOWN & CASHIER PERFORMANCE -->
  <div class="section-title">Breakdowns</div>
  <table class="panel-table" cellpadding="0" cellspacing="0">
    <tr>
      <td width="33%">
        <div class="panel">
          <div class="panel-title">Payment Breakdown</div>
          <table class="mini-table" cellpadding="0" cellspacing="0">
            <thead><tr><th>Payment Mode</th><th class="num">Amount</th></tr></thead>
            <tbody>
              {% for row in payment_breakdown %}
              <tr>
                <td style="font-weight:600;">{{ row.mode or 'Unknown' }}</td>
                <td class="num" style="color:#15803d;font-weight:700;">&#x20a6;{{ "{:,.2f}".format(row.amount | float) }}</td>
              </tr>
              {% else %}
              <tr><td colspan="2" style="color:#9ca3af;font-style:italic;padding:8px 0;">No payment breakdown.</td></tr>
              {% endfor %}
            </tbody>
          </table>
        </div>
      </td>
      <td width="33%" style="padding-left:6px;">
        <div class="panel">
          <div class="panel-title">Cashier Performance</div>
          <table class="mini-table" cellpadding="0" cellspacing="0">
            <thead><tr><th>Cashier</th><th class="num">Orders</th><th class="num">Sales</th></tr></thead>
            <tbody>
              {% for row in cashier_performance %}
              <tr>
                <td style="font-weight:600;">{{ row.cashier or 'Unknown' }}</td>
                <td class="num">{{ row.orders or 0 }}</td>
                <td class="num" style="font-weight:700;">&#x20a6;{{ "{:,.2f}".format(row.sales | float) }}</td>
              </tr>
              {% else %}
              <tr><td colspan="3" style="color:#9ca3af;font-style:italic;padding:8px 0;">No cashier data.</td></tr>
              {% endfor %}
            </tbody>
          </table>
        </div>
      </td>
      <td width="33%" style="padding-left:6px;padding-right:0;">
        <div class="panel">
          <div class="panel-title">Top Selling Items</div>
          <table class="mini-table" cellpadding="0" cellspacing="0">
            <thead><tr><th>Item</th><th class="num">Qty</th><th class="num">Revenue</th></tr></thead>
            <tbody>
              {% for item in top_items %}
              <tr>
                <td style="font-weight:600;">{{ item.item_name or item.item_code or 'Unknown' }}</td>
                <td class="num">{{ item.qty or 0 }}</td>
                <td class="num" style="font-weight:700;">&#x20a6;{{ "{:,.2f}".format(item.revenue | float) }}</td>
              </tr>
              {% else %}
              <tr><td colspan="3" style="color:#9ca3af;font-style:italic;padding:8px 0;">No item data.</td></tr>
              {% endfor %}
            </tbody>
          </table>
        </div>
      </td>
    </tr>
  </table>

  <!-- SHIFT PERFORMANCE -->
  {% if shifts %}
  <div class="section-title">Shift Performance</div>
  <table class="data-table" cellpadding="0" cellspacing="0">
    <thead>
      <tr>
        <th>Shift</th><th>Cashier</th><th>Opening</th><th>Closing</th>
        <th class="num">Orders</th><th class="num">Sales</th><th class="num">Variance</th>
      </tr>
    </thead>
    <tbody>
      {% for shift in shifts %}
      <tr>
        <td><span class="ref">{{ shift.name or '&mdash;' }}</span></td>
        <td style="font-weight:600;">{{ shift.cashier or 'Unknown' }}</td>
        <td style="color:#6b7280;font-size:7pt;">{{ shift.opening_time or '&mdash;' }}</td>
        <td style="color:#6b7280;font-size:7pt;">{{ shift.closing_time or 'Open' }}</td>
        <td class="num">{{ shift.orders or 0 }}</td>
        <td class="num" style="font-weight:600;">&#x20a6;{{ "{:,.0f}".format(shift.sales | float) }}</td>
        <td class="num {% if shift.variance | float < 0 %}style="color:#dc2626;font-weight:700;"{% else %}style="color:#15803d;font-weight:700;"{% endif %}">
          &#x20a6;{{ "{:,.0f}".format(shift.variance | float) }}
        </td>
      </tr>
      {% endfor %}
    </tbody>
  </table>
  {% endif %}

  <!-- DETAILED SALES -->
  <div class="section-title">Detailed POS Sales &mdash; {{ sales | length }} record(s)</div>
  {% if sales %}
  <table class="data-table" cellpadding="0" cellspacing="0">
    <thead>
      <tr>
        <th class="ctr">#</th><th>Invoice</th><th>Date</th><th>Guest / Customer</th>
        <th>Room</th><th>Cashier</th><th>POS Profile</th><th>Payment</th>
        <th class="num">Gross</th><th class="num">Discount</th>
        <th class="num">Tax</th><th class="num">Net</th><th>Status</th>
      </tr>
    </thead>
    <tbody>
      {% for sale in sales %}
      <tr>
        <td class="ctr" style="color:#9ca3af;">{{ loop.index }}</td>
        <td><span class="ref">{{ sale.invoice or '&mdash;' }}</span></td>
        <td style="color:#6b7280;white-space:nowrap;font-size:7pt;">{{ sale.date or '&mdash;' }}</td>
        <td style="font-weight:600;">{{ sale.customer or 'Walk-in Customer' }}</td>
        <td style="color:#6b7280;">{{ sale.room or '&mdash;' }}</td>
        <td style="color:#6b7280;">{{ sale.cashier or 'Unknown' }}</td>
        <td style="color:#6b7280;font-size:7pt;">{{ sale.pos_profile or '&mdash;' }}</td>
        <td style="color:#6b7280;">{{ sale.payment_mode or 'Unknown' }}</td>
        <td class="num" style="font-weight:600;">&#x20a6;{{ "{:,.0f}".format(sale.gross_amount | float) }}</td>
        <td class="num" style="color:#d97706;">&#x20a6;{{ "{:,.0f}".format(sale.discount | float) }}</td>
        <td class="num" style="color:#6b7280;">&#x20a6;{{ "{:,.0f}".format(sale.tax | float) }}</td>
        <td class="num" style="font-weight:700;">&#x20a6;{{ "{:,.0f}".format(sale.net_amount | float) }}</td>
        <td>
          {% set s = sale.status or '' %}
          {% if s == 'Paid' %}<span class="badge badge-paid">Paid</span>
          {% elif s == 'Part Payment' %}<span class="badge badge-part">Part</span>
          {% elif s == 'Unpaid' %}<span class="badge badge-unpaid">Unpaid</span>
          {% elif s == 'Posted to Room' %}<span class="badge badge-room">Room</span>
          {% else %}<span class="badge badge-muted">{{ s or '&mdash;' }}</span>{% endif %}
        </td>
      </tr>
      {% endfor %}
    </tbody>
    <tfoot>
      <tr>
        <td colspan="8" style="text-align:right;text-transform:uppercase;letter-spacing:0.5px;">Grand Total</td>
        <td class="num">&#x20a6;{{ "{:,.0f}".format(totals.gross_amount | float) }}</td>
        <td class="num" style="color:#fde68a;">&#x20a6;{{ "{:,.0f}".format(totals.discount | float) }}</td>
        <td class="num">&#x20a6;{{ "{:,.0f}".format(totals.tax | float) }}</td>
        <td class="num">&#x20a6;{{ "{:,.0f}".format(totals.net_amount | float) }}</td>
        <td></td>
      </tr>
    </tfoot>
  </table>
  {% else %}
  <p style="padding:16px;text-align:center;color:#9ca3af;font-size:8.5pt;border:1px dashed #e5e7eb;">No POS sales records found for the selected filters.</p>
  {% endif %}

  <!-- FOOTER -->
  <hr class="footer-divider" />
  <table width="100%" cellpadding="0" cellspacing="0">
    <tr>
      <td width="60%" valign="bottom">
        <div class="footer-note">
          This report is generated by the {{ company }} Property Management System.<br>
          POS note: Monitor discounts, room posting, cashier variance, unpaid invoices and shift closure accuracy.<br>
          <strong style="color:#374151;">Period: {{ filters.date_from }} to {{ filters.date_to }}</strong>
        </div>
      </td>
      <td valign="bottom" align="right">
        <div class="footer-company">{{ company }}</div>
        <div class="footer-date">{{ generated_at }}</div>
        <div class="sig-line">Authorised Signature</div>
      </td>
    </tr>
  </table>

</div>
</body>
</html>"}
